/**
 * @summary Create or replace the draft for a case
 */
export const getUpsertDraftUrl = (caseId: string) => {
  return `/api/v1/cases/${caseId}/draft`;
};

export const upsertDraft = async (
  caseId: string,
  upsertDraftBody: UpsertDraftBody,
  options?: RequestInit,
): Promise<Draft> => {
  return customFetch<Draft>(getUpsertDraftUrl(caseId), {
    ...options,
    method: "PUT",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(upsertDraftBody),
  });
};

export const getUpsertDraftMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof upsertDraft>>,
    TError,
    { caseId: string; data: BodyType<UpsertDraftBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof upsertDraft>>,
  TError,
  { caseId: string; data: BodyType<UpsertDraftBody> },
  TContext
> => {
  const mutationKey = ["upsertDraft"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof upsertDraft>>,
    { caseId: string; data: BodyType<UpsertDraftBody> }
  > = (props) => {
    const { caseId, data } = props ?? {};

    return upsertDraft(caseId, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type UpsertDraftMutationResult = NonNullable<
  Awaited<ReturnType<typeof upsertDraft>>
>;
export type UpsertDraftMutationBody = BodyType<UpsertDraftBody>;
export type UpsertDraftMutationError = ErrorType<unknown>;

/**
 * @summary Create or replace the draft for a case
 */
export const useUpsertDraft = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof upsertDraft>>,
    TError,
    { caseId: string; data: BodyType<UpsertDraftBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof upsertDraft>>,
  TError,
  { caseId: string; data: BodyType<UpsertDraftBody> },
  TContext
> => {
  return useMutation(getUpsertDraftMutationOptions(options));
};
